    multiset<int>::iterator it;

    for(int i = 0; i < n; i++) {

        if(s.empty()) {

            s.insert(-P[i].r);

        } else {

            it = s.lower_bound(-P[i].l);

            if(it == s.end()) {

                s.insert(-P[i].r);

